safe_encoding.template:
// PHP example:
echo htmlspecialchars({{var}}, ENT_QUOTES, 'UTF-8');

// JavaScript example:
const safeOutput = {{var}}.replace(/[<>"'&]/g, (char) => ({
  '<': '&lt;',
  '>': '&gt;',
  '"': '&quot;',
  "'": '&#x27;',
  '&': '&amp;'
}[char]));

generic_escape.template:
// Escape karakter berbahaya:
const safe{{Var}} = {{var}}.replace(/[<>"'&]/g, (char) => ({
  '<': '&lt;',
  '>': '&gt;',
  '"': '&quot;',
  "'": '&#x27;',
  '&': '&amp;'
}[char]));

document.write(safe{{Var}});

